INSERT INTO public.welfare_regions (id, name, description, population_youth, avg_rent_officetel, keywords)
VALUES 
('gangnam-gu', '강남구', '글로벌 비즈니스의 중심, 고사양 인프라와 프리미엄 청년 지원 정책이 풍부한 지역입니다.', 150000, 850000, ARRAY['비즈니스', '스타트업', '테헤란로']),
('gangdong-gu', '강동구', '쾌적한 주거 환경과 고덕비즈밸리를 중심으로 취업 지원이 활발한 활력 넘치는 지역입니다.', 120000, 550000, ARRAY['주거중심', '고덕밸리', '한강']),
('gangbuk-gu', '강북구', '북한산의 정기와 함께 대학가 청년 문화를 선도하는 가성비 주거의 성지입니다.', 80000, 420000, ARRAY['북한산', '대학가', '가성비']),
('gangseo-gu', '강서구', '마곡 마이스(MICE) 산업의 심장부로, IT 청년들을 위한 직주근접 정책이 우수합니다.', 180000, 520000, ARRAY['마곡지구', '김포공항', 'IT']),
('gwanak-gu', '관악구', '서울 청년 인구 비율 1위, 고시촌에서 벤처밸리로 진화하는 청년 성취의 요람입니다.', 200000, 480000, ARRAY['청년밀집', '벤처밸리', '낙성대']),
('gwangjin-gu', '광진구', '건국대/세종대 대학가와 뚝섬 한강공원을 품은 낭만과 창업의 공존 구역입니다.', 110000, 500000, ARRAY['건대입구', '군자', '한강공원']),
('guro-gu', '구로구', 'G-밸리의 디지털 창의성이 지배하는 곳, IT 제조와 소프트웨어 청년들의 기지입니다.', 130000, 450000, ARRAY['G밸리', '디지털단지', '네트워크']),
('geumcheon-gu', '금천구', '가산디지털단지의 활력과 함께 청년 창업가들을 위한 인큐베이팅 공간이 많습니다.', 90000, 430000, ARRAY['가산디지털', '패션IT', '스타트업']),
('nowon-gu', '노원구', '교육 특구이자 주거 지역으로, 청년 인턴쉽과 구직 활동 지원이 꼼꼼한 지역입니다.', 140000, 400000, ARRAY['교육특구', '문화도시', '경춘선숲길']),
('dobong-gu', '도봉구', '창동역 아레나를 중심으로 문화 예술 청년들이 모여드는 새로운 창작의 거점입니다.', 70000, 380000, ARRAY['씨드큐브', '문화예술', '도봉산']),
('dongdaemun-gu', '동대문구', '경희대/외대 등 다수의 대학이 운집하여 글로벌 청년 교류가 가장 활발한 구역입니다.', 100000, 440000, ARRAY['대학벨트', '글로벌', '청량리역']),
('dongjak-gu', '동작구', '노량진의 합격 에너지와 중앙대/숭실대의 젊음이 만나는 도전의 장소입니다.', 120000, 530000, ARRAY['노량진', '합격의도시', '흑석']),
('mapo-gu', '마포구', '홍대/신촌의 창의 문화와 상암 DMC의 미디어가 융합된 MZ세대의 소울 플레이스입니다.', 160000, 650000, ARRAY['홍대', 'DMC', '연남동']),
('seodaemun-gu', '서대문구', '연세대/이화여대 기반의 역사적 대학촌으로, 청년들의 실험 정신이 꽃피는 곳입니다.', 110000, 480000, ARRAY['신촌', '연희동', '독립문']),
('seocho-gu', '서초구', '문화예술의 전당과 법조 단지를 아우르는, 안정감과 고품격 서초형 지원이 돋보입니다.', 130000, 750000, ARRAY['예술의전당', '양재AI', '고속터미널']),
('seongdong-gu', '성동구', '성수동의 힙한 감성과 지식산업센터의 효율이 공존하는 창조적 직주근접의 모델입니다.', 100000, 680000, ARRAY['성수동', '서울숲', '지식산업']),
('seongbuk-gu', '성북구', '성북동의 전통과 고려대/국민대의 지성이 만나는 평화로우면서도 역동적인 구역입니다.', 110000, 430000, ARRAY['성북천', '가고싶은동네', '대학문화']),
('songpa-gu', '송파구', '롯데월드타워와 석촌호수의 여유, 문정 법조타운의 전문직 청년들이 선호하는 지역입니다.', 210000, 620000, ARRAY['석촌호수', '잠실', '문정밸리']),
('yangcheon-gu', '양천구', '목동의 안정된 인프라를 바탕으로 청년 1인 가구의 삶의 질 개선에 진심인 곳입니다.', 120000, 480000, ARRAY['목동', '주거안정', '안양천']),
('yeongdeungpo-gu', '영등포구', '여의도 금융권과 문래 창작촌의 이질적 매력이 조화된, 가능성이 무궁무진한 공간입니다.', 140000, 580000, ARRAY['여의도', '타임스퀘어', '문래동']),
('yongsan-gu', '용산구', '국제 업무 지구와 한남동의 감각이 만나는, 서울의 중심이자 청년들의 꿈이 실현되는 곳입니다.', 80000, 720000, ARRAY['이태원', '용리단길', '남산']),
('eunpyeong-gu', '은평구', '불광천의 여유와 혁신파크의 도전이 함께하는, 1분 거리에 자연이 숨 쉬는 도심 숲세권입니다.', 130000, 420000, ARRAY['혁신파크', '불광천', '연신내']),
('jongno-gu', '종로구', '전통과 현대가 춤추는 대한민국 문화의 심장부로, 청년 전통 창업가들의 발상지입니다.', 40000, 580000, ARRAY['경복궁', '인사동', '익선동']),
('jung-gu', '중구', '명동과 을지로의 활기가 넘치는 곳, 힙지로 만의 감성으로 가득한 청년 상인들의 성지입니다.', 40000, 600000, ARRAY['힙지로', '동대문시장', '남산']),
('jungnang-gu', '중랑구', '면목동 생활권과 상봉역 교통 거점을 중심으로 실질적인 주거비 절감 혜택이 많은 동네입니다.', 100000, 390000, ARRAY['망우역', '장미축제', '주거복지'])
